import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import './BookCard.css';

const CATEGORY_COLORS = {
  Fiction:        '#c9a84c',
  'Non-Fiction':  '#4caf82',
  Science:        '#5b8dee',
  History:        '#c47c5a',
  Technology:     '#9b72cf',
  Romance:        '#d4709a',
  Mystery:        '#7a9e9f',
  Programming:    '#e07b39',
  Biography:      '#6bbd6b',
  'Self-Help':    '#d4a84c',
};

export default function BookCard({ book, onEdit, onDelete, onAddToCart, isAdmin, isLoggedIn }) {
  const [adding, setAdding] = useState(false);
  const [added,  setAdded]  = useState(false);

  const color   = CATEGORY_COLORS[book.category] || '#c9a84c';
  const initial = (book.title || 'B')[0].toUpperCase();
  const inStock = book.stock > 0;

  const handleAddToCart = async () => {
    if (!onAddToCart || adding || added) return;
    setAdding(true);
    try {
      await onAddToCart(book);
      setAdded(true);
      // Reset after 2 seconds so user can add again
      setTimeout(() => setAdded(false), 2000);
    } catch {
      // error handled in parent
    } finally {
      setAdding(false);
    }
  };

  return (
    <div className="book-card fade-up">
      {/* Cover */}
      <div className="book-cover" style={{ '--accent': color }}>
        <div className="book-spine" style={{ background: color }} />
        <div className="book-initial">{initial}</div>
        <div className="book-category-tag">{book.category || 'General'}</div>
        {!inStock && (
          <div className="book-out-of-stock">Out of Stock</div>
        )}
      </div>

      {/* Info */}
      <div className="book-info">
        <h3 className="book-title">{book.title}</h3>
        <p className="book-author">by {book.author}</p>

        <div className="book-meta">
          <span className="book-price">₹{book.price?.toFixed(2)}</span>
          <span className="book-stock" style={{ color: inStock ? 'var(--green)' : 'var(--red)' }}>
            {inStock ? `${book.stock} in stock` : 'Out of stock'}
          </span>
        </div>

        {/* Actions */}
        <div className="book-actions">
          {/* View button — always visible */}
          <Link to={`/books/${book.id}`} className="btn btn-outline btn-xs">
            View
          </Link>

          {/* Add to Cart — only for logged-in non-admin users on in-stock books */}
          {isLoggedIn && !isAdmin && inStock && (
            <button
              className={`btn btn-xs btn-cart ${added ? 'btn-cart-added' : ''}`}
              onClick={handleAddToCart}
              disabled={adding || added}
            >
              {adding ? '…' : added ? '✓ Added' : '🛒 Add to Cart'}
            </button>
          )}

          {/* Admin controls */}
          {isAdmin && (
            <>
              <button
                className="btn btn-ghost btn-xs"
                onClick={() => onEdit(book)}
              >
                Edit
              </button>
              <button
                className="btn btn-danger btn-xs"
                onClick={() => onDelete(book.id)}
              >
                Delete
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
